using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();

var app = builder.Build();

// Copy CSV to output directory if running from source
var dataDir = Path.Combine(AppContext.BaseDirectory, "Data");
Directory.CreateDirectory(dataDir);
var sourceCSV = Path.Combine(Directory.GetCurrentDirectory(), "Data", "tickets.csv");
var destCSV = Path.Combine(dataDir, "tickets.csv");
if (File.Exists(sourceCSV) && !File.Exists(destCSV))
    File.Copy(sourceCSV, destCSV);

// Train model at startup and register PredictionEnginePool
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
var modelPath = trainer.TrainAndEvaluate();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

// Rebuild services to include the prediction pool
app = builder.Build();

app.MapControllers();
app.Run();

