using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public record TrainResult(string ModelPath, string[] LabelNames);

public class TicketModelTrainer
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(IConfiguration configuration, ILogger<TicketModelTrainer> logger)
    {
        _dataPath = configuration.GetValue<string>("MLModel:DataPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = configuration.GetValue<string>("MLModel:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public TrainResult TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {Path}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        // Extract label names from the Score column metadata
        var allDataPredictions = model.Transform(data);
        var scoreColumn = allDataPredictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        _logger.LogInformation("Label order: {Labels}", string.Join(", ", labelNames));

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        return new TrainResult(_modelPath, labelNames);
    }
}

